export async function createSwapApp({
  rpcUrl,
  routerAddress,
  chainId = null,
  windowEthereum = typeof window !== "undefined" ? window.ethereum : undefined,
}) {
  const app = await TokenSwapDApp.connect({ rpcUrl, routerAddress, chainId });
  if (windowEthereum) {
    await app.connectWallet(windowEthereum);
  }
  return app;
}

export async function formatTokenAmount(tokenAddress, rawAmount, provider) {
  const token = new ethers.Contract(tokenAddress, ERC20_ABI, provider);
  const decimals = await token.decimals().catch(() => 18);
  return ethers.formatUnits(rawAmount, decimals);
}

export async function parseTokenAmount(tokenAddress, amount, provider) {
  const token = new ethers.Contract(tokenAddress, ERC20_ABI, provider);
  const decimals = await token.decimals().catch(() => 18);
  return ethers.parseUnits(amount.toString(), decimals);
}

export function isApprovalNeeded(allowance, amountIn) {
  return allowance < amountIn;
}

export function maxApprovalAmount() {
  return MAX_UINT256;
}